# This is a decorator to protect endpoints in Flask-restful API. It checks for a token in the session dict.
def require_oauth(f):

    @wraps(f) 
    def decorated(*args, **kwargs):

        if "token" not in session:
            return jsonify({"error":"invalid authorization"}),401

        return f(*args,**kwargs)
    return decorated


